mapper.select:
/* mPlatformMapper.getXmlMessageST1 */
SELECT  OSST_ORD_NO AS osstOrdNo
FROM    MCP_REQUEST_OSST A
WHERE   MVNO_ORD_NO = #{mvnoOrdNo}
AND     SEQ = (SELECT MAX(SEQ) FROM MCP_REQUEST_OSST WHERE MVNO_ORD_NO = A.MVNO_ORD_NO AND PRGR_STAT_CD = 'PC2' AND RSLT_CD = '0000')
AND     ROWNUM = 1

mapper.insert:
/* mPlatformMapper.insertRequestOsst */
INSERT INTO MCP_REQUEST_OSST (
    MVNO_ORD_NO
    , SEQ
    , OSST_ORD_NO
    , PRGR_STAT_CD
    , RSLT_CD
    , RSLT_MSG
    , RSLT_DT
    , NSTEP_GLOBAL_ID
    , PRDC_CHK_NOTI_MSG
    , IF_TYPE
    , REGST_DTTM
) VALUES (
    LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0')
    , NVL((SELECT MAX(SEQ) + 1 FROM MCP_REQUEST_OSST WHERE MVNO_ORD_NO = LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0')), 1)
    , #{osstOrdNo, jdbcType=VARCHAR}
    , #{appEventCd, jdbcType=VARCHAR}
    , #{rsltCd, jdbcType=VARCHAR}
    , #{rsltMsg, jdbcType=VARCHAR}
    , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
    , #{nstepGlobalId, jdbcType=VARCHAR}
    , #{prdcChkNotiMsg, jdbcType=VARCHAR}
    , 'WEB'
    , SYSDATE
)

mapper.update:
/* mPlatformMapper.updateRequestAddition */
UPDATE  MCP_REQUEST_ADDITION
SET     PROC_YN = 'P'
WHERE   REQUEST_KEY = #{requestKey}
AND     ADDITION_KEY = #{additionKey}

mapper.insert:
/* mPlatformMapper.insertSelfCareLog */
INSERT INTO MCP_MPLATFORM_LOG (
    MDL_IND
    , EVENT_CODE
    , CONTRACT_NUM
    , ACCESS_URL
    , ACCESS_IP
    , USER_ID
    , EXPNSN_STR_VAL1
    , SYS_DT
    , SYS_RDATE
    , YY
    , MM
    , DD
) VALUES (
    NVL(#{mdlInd, jdbcType=VARCHAR}, 'IVR')
    , #{appEventCd, jdbcType=VARCHAR}
    , #{ncn, jdbcType=VARCHAR}
    , #{url, jdbcType=VARCHAR}
    , #{ip, jdbcType=VARCHAR}
    , #{userid, jdbcType=VARCHAR}
    , #{expnsnStrVal1, jdbcType=VARCHAR}
    , TO_CHAR(SYSDATE, 'YYYYMMDD')
    , SYSDATE
    , TO_CHAR(SYSDATE, 'YYYY')
    , TO_CHAR(SYSDATE, 'MM')
    , TO_CHAR(SYSDATE, 'DD')
)

mapper.select:
        /* mPlatformMapper.getMplatformCryptionYn mp암복호화 여부 */
		SELECT USE_YN
		  FROM NMCP_CD_DTL
		 WHERE CD_GROUP_ID = 'MpCryptionYn'
		   AND DTL_CD = #{eventCd, jdbcType=VARCHAR}

mapper.insert:
/* mPlatformMapper.insertOsstErrLog OSST exception 이력 저장 */

    SELECT TO_NUMBER(TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(SQ_OSST_ERR_LOG_SEQ.NEXTVAL, '000000'))) FROM DUAL

INSERT INTO NMCP_OSST_ERR_LOG (
   SEQ
  ,RES_NO
  ,PRGR_STAT_CD
  ,PRNTS_CONTRACT_NO
  ,CUSTOMER_ID
  ,ERR_TYPE
  ,ERR_MSG
  ,REGST_DT
  ,REGST_DTTM
) VALUES (
   #{seq}
  ,#{resNo}
  ,#{prgrStatCd}
  ,#{prntsContractNo}
  ,#{customerId}
  ,#{errType}
  ,#{errMsg}
  ,TO_CHAR(SYSDATE, 'YYYYMMDD')
  ,SYSDATE
)
